"""
MKT Christ Commentary — Hebrews chapters 1–5 (gap-fill pass)
Run: python3 scripts/zc-christ-hebrews-1-5-gaps.py

Key decisions:
- ch1 catena: each OT citation reveals Christ directly or by contrast; angels reveal by negation
- ch2 Ps 8: type fulfilled in Christ's incarnation-humiliation and resurrection-exaltation
- ch3 warning sections: theme — negative type of wilderness generation exposes faith-structure
- ch4 rest theology: creation Sabbath as type; Joshua as type pointing beyond to Jesus
- ch5 Levitical priesthood: institutional type — each feature points to Christ by correspondence or contrast
- Directness levels used: direct (explicit NT application), type (OT institution/person), theme (shared pattern), revelation of God (divine character disclosed)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = json.loads(r"""
{
  "1": {
    "4": "<p>A direct revelation: having become as much superior to the angels as the name he has inherited is more excellent than theirs. The exaltation declares what was always true of the Son but is now publicly enacted in human history — the Son's name (\"Son of God\" in the fullest sense) surpasses every angelic title because it is the name above every name (Phil 2:9). The word \"having become\" (<em>genomenos</em>) does not imply the Son became something he was not, but that the resurrection-exaltation publicly established in human history what the Son eternally is.</p>",
    "6": "<p>A fulfillment: when God brings the firstborn into the world, the angels are commanded to worship him. This is the eschatological fulfillment of the divine decree — at the incarnation and/or the parousia, the entire angelic host pays homage to the Son who entered the human order. The same creator before whom the angels stood as servants now appears as the enfleshed firstborn, receiving their worship. The divine command that all bow before the Son (from Deut 32:43 LXX / Ps 97:7) is the universe's acknowledgment of the Son's unique status.</p>",
    "7": "<p>A revelation of God: the angels are characterized as winds and flames — changeable, elemental, creaturely. The contrast with the eternal Son is between the natural order (which angels govern and represent) and the one who stands outside the natural order as its maker. This verse reveals by contrast: what the angels are (mutable servants) defines negatively what the Son is (the immutable Lord). Every creaturely attribute reveals its own limitation and thereby points to the uncreated one who transcends it.</p>",
    "8": "<p>A direct revelation: God addresses the Son as \"God\" — \"Your throne, O God, is forever and ever.\" The Christological claim embedded in the Psalm 45 citation is among the strongest direct divine-title applications in the NT: the Father addresses the Son with the divine name. The eternal throne and the scepter of righteousness are the Son's royal attributes disclosed through the Psalm's direct address. This is not typological prediction but direct speech — God speaks to the Son and calls him God.</p>",
    "9": "<p>A revelation of God: the anointing of the Son with the oil of gladness beyond his companions reveals the character of the Messiah — the anointed one is characterized by loving righteousness and hating wickedness. The <em>chriō</em> verb (to anoint) behind <em>christos</em> connects the eternal Son's moral character with the title by which he is known: the Christ is the righteously-anointed one. His gladness surpassing all others is the eschatological joy of the one who has done perfectly what all others have done partially.</p>",
    "10": "<p>A revelation of God: the Lord who laid the foundations of the earth in the beginning is the same Lord whose years will never end — the creator is identified as the Son. This Yahweh-Psalm is applied to Christ, revealing his divine identity as creator and eternal sustainer. The argument from creation is the deepest possible Christological claim: the one who made the heavens and the earth is present now in human history as the redeemer, completing from within creation what he began as creator.</p>",
    "11": "<p>A revelation of God: they will perish, but you remain. The contrast between the perishing creation and the abiding Son reveals the ontological distinction between creator and creature. Everything that was made will wear out; the Son who made it will not. This verse is not primarily about the Son's relationship to creation but about his nature — the indestructible permanence of the one who is not subject to the processes of decay and dissolution that govern all created things.</p>",
    "12": "<p>A revelation of God: the Son who rolls up the heavens as a garment is the same Son whose years will never end. The eschatological act of rolling up creation like a worn-out cloak is the act of the Lord who is <em>ho autos</em> — the same, unchanged, unaffected by the processes that bring creation to its end. Christ's immutability is not detachment from creation but the transcendence that enables him to dispose of creation at the appointed time and bring his people into the eternal order.</p>",
    "14": "<p>A revelation of God: the angels are ministering spirits sent to serve those who will inherit salvation. The Christological revelation here is indirect but decisive: the entire angelic service-system exists for the benefit of the community that belongs to the Son. The angels serve not because the community is great in itself but because they are Christ's people — the inheritance of the Son defines their status, and the angelic service is the extension of the Son's own provision for those he redeems.</p>"
  },
  "2": {
    "1": "<p>A theme: the call to pay closest attention to what has been heard because the message is greater than the angels' message reflects the pattern of the entire OT-to-NT escalation that Christ's coming represents. Each warning passage in Hebrews is itself Christological: to neglect this salvation is to neglect the Son who announced it and the Father who confirmed it. The warning is addressed to those who have heard the Son's word and must now remain in it.</p>",
    "2": "<p>A theme: the law declared through angels was reliable and carried just recompense. This establishes the lower rung of the two-level argument: if the lesser (angelic/Mosaic) word carried binding force, how much more the word of the Son. The reliability of the Mosaic covenant's penalties is the argumentative basis for the severity of neglecting the Son's greater covenant. The law's authority serves as the measure against which the gospel's greater authority is calibrated.</p>",
    "4": "<p>A direct revelation: God confirmed the salvation-message through signs, wonders, miracles, and distributions of the Holy Spirit according to his will. The Trinitarian confirmation — Son announces, Father confirms, Spirit distributes — is the community's foundation for certainty. These confirmatory signs were the Spirit's testimony to the Son's identity and the Father's approval. The community that experienced these gifts stands on the ground of the Triune God's own attestation of the salvation in his Son.</p>",
    "5": "<p>A revelation of God: God did not subject the coming world to angels. This prepares the Christological argument: the world-to-come belongs to Christ, not to the angels. The age-to-come, for which the entire creation groans (Rom 8:22), is the domain of the Son's lordship. The angels governed aspects of the present age; the new creation is Christ's inheritance, the world into which he leads his people as their forerunner-pioneer.</p>",
    "6": "<p>A type: Psalm 8's \"What is man?\" establishes the pattern of human humiliation and exaltation over creation that finds its fulfillment in Christ. The Psalm begins with human smallness before the vast creation and ends with human dominion over it — a trajectory that describes both human vocation and the gap between vocation and reality. Christ is the one who closes this gap: the man who fully inhabits the human vocation of dominion-through-faithful-service.</p>",
    "7": "<p>A fulfillment: \"You made him a little lower than the angels; you crowned him with glory and honor\" — Christ's incarnation (made lower) and resurrection-exaltation (crowned with glory) fulfill the Psalm 8 trajectory. The LXX's \"little lower\" carries both a degree sense (slightly lower in status) and a temporal sense (for a little while) — both dimensions apply to the incarnation: the Son was genuinely lower in his human condition, and genuinely for a limited time. The crowning is the public event of the exaltation that reverses the humiliation.</p>",
    "8": "<p>A fulfillment (not yet complete): \"You have put everything under his feet\" — the Psalm 8 promise of universal dominion is already enacted in principle (at the resurrection) but not yet visibly complete (\"at present we do not see everything subject to him\"). This \"already-not-yet\" tension is the Christological structure of the present age: Christ reigns, but the reign is not yet universally acknowledged. The community lives between the \"already\" of the resurrection and the \"not yet\" of the parousia-consummation.</p>",
    "10": "<p>A direct revelation: it was fitting for God to make the pioneer of salvation perfect through suffering. The sufferings of Christ are not a theological problem to be explained away but the fitting and necessary path by which the Son became the completed, qualified, vocational high priest. The perfection through suffering is not moral improvement but the full traversal of the human path — from birth through death and into resurrection — that enables him to lead many sons and daughters to glory.</p>",
    "11": "<p>A direct revelation: the one who sanctifies and those who are sanctified are all from one Father, which is why Jesus is not ashamed to call them brothers and sisters. The shared origin in one Father is the basis of the family solidarity that defines salvation: the Son who sanctifies enters into genuine kinship with those he sanctifies. He is not ashamed of this solidarity even though it means identifying with the lowly, the failing, the mortal. This is the Christological heart of the atonement: real solidarity, real kinship, real brotherhood.</p>",
    "12": "<p>A fulfillment: the risen Christ fulfills Psalm 22:22 by proclaiming the Father's name to his brothers and sisters and singing praise in the midst of the assembly. The Psalm that begins with the cry of dereliction (\"My God, my God, why have you forsaken me?\" — quoted at the cross) ends with the promise of praise in the assembly. The resurrection is the fulfillment of the Psalm's turn from abandonment to vindication; the risen Christ's proclamation of the Father's name in the community's worship is the enacted fulfillment of the Psalm's final movement.</p>",
    "13": "<p>A fulfillment: the two Isaiah 8 citations — \"I will trust in him\" and \"Here am I and the children God has given me\" — are fulfilled in Christ's own posture of trust toward the Father through suffering and in his identification with the community he redeems. Isaiah 8's righteous remnant who trusts while God hides his face is the OT pattern; Christ is the definitive fulfillment: the one who trusts the Father through the cross and presents to the Father the community entrusted to him.</p>",
    "15": "<p>A direct revelation: through his death Christ sets free those who all their lives were held in slavery by their fear of death. The liberation is comprehensive — not merely from death itself but from the enslaving anxiety that death-as-threat produces throughout human life. Christ's death destroys the mechanism by which the devil held humanity enslaved: the fear of death as the ultimate sanction loses its power when the one who entered death defeated it from within.</p>",
    "16": "<p>A fulfillment: it is not angels he helps, but Abraham's descendants — the Son's incarnation was targeted at the specific covenant community of Abraham's seed, fulfilling the Abrahamic promise by entering the family line it promised. The gospel's particularity (Jesus was a Jewish man from the tribe of Judah, born of a woman under the law) is the fulfillment strategy: the universal salvation comes through the particular covenantal trajectory of Abraham's seed. The heir of all things (1:2) comes as Abraham's descendant to fulfill what was promised to Abraham.</p>",
    "18": "<p>A direct revelation: because he suffered when he was tempted, he is able to help those who are being tempted. The incarnation gave Christ a permanent qualification: the tested high priest who knows temptation from within. This is not generic divine knowledge of human experience but the specific, earned qualification of the one who walked through every test. His help is not distant sympathy but the active aid of the one who has already been where those he helps are now.</p>"
  },
  "3": {
    "2": "<p>A type: Moses was faithful in God's house — his faithfulness is the shadow of Christ's superior faithfulness. The comparison begins with what Moses and Christ share (both were faithful to the one who appointed them) before establishing the distinction (servant in the house vs. Son over the house). Moses is not depreciated but honored as the type whose faithful service pointed forward to the antitype whose faithfulness surpasses it.</p>",
    "3": "<p>A direct revelation: Jesus has been counted worthy of more glory than Moses, just as the builder of a house has more honor than the house. The builder/house relationship is the Christological key: Moses was part of the house that Christ built. This means the Mosaic covenant and its entire institutional structure — the tabernacle, the priesthood, the sacrificial system — is the creation of the Son, not the other way around. Christ did not emerge from within the Mosaic system; the Mosaic system emerged from and within Christ's creative wisdom.</p>",
    "4": "<p>A revelation of God: every house is built by someone, but the builder of all things is God. This establishes the divine identity of the Son who built God's house (v3): since God is the builder of everything, and the Son built the house, the Son participates in divine building. The logic is not explicit but is implicit: the Son who built the house partakes of the divine builder-identity that v4 predicates of God alone. Hebrews' high Christology emerges through this kind of connective reasoning from divine attributes.</p>",
    "7": "<p>A theme: \"Today, if you hear his voice\" — the Holy Spirit's ongoing address through Psalm 95 is itself a Christological claim. The Spirit speaks the invitation to enter Christ's rest in every generation. The \"voice\" the community must not harden against is the voice of the one who speaks in the Son (1:2) — the same triune speaking that grounds the entire letter's argument is at work in the Psalm's repeated \"today.\"</p>",
    "8": "<p>A theme: \"Do not harden your hearts as in the rebellion\" — the wilderness generation's hardening against God's voice is the negative type whose positive counterpart is faith-reception of the Son's word. The wilderness generation heard God but refused; the community addressed by Hebrews has heard the Son but is in danger of refusing. The structural parallel makes the wilderness generation's failure a mirror for the community's own situation.</p>",
    "9": "<p>A theme: the forty years of wilderness testing reveals the pattern of seeing divine works and still refusing to trust. This is the negative pattern against which Christ's faithfulness stands out: where Israel tested God despite seeing his works, Christ was faithful to God through every test. The wilderness generation's failure is both a warning and an implicit commendation of the one who succeeded where they failed.</p>",
    "10": "<p>A theme: \"Their hearts are always going astray, and they have not known my ways\" — the failure of the wilderness generation to know God's ways is the condition that the new covenant addresses by writing God's law on the heart (Jer 31:33). Christ inaugurates the new covenant whose internalized law overcomes the heart-wandering that doomed the wilderness generation. The diagnosis of the problem (wandering heart, unknown ways) is the setup for the solution (Christ as the way, the truth, the life; Jer 31 as the remedy).</p>",
    "11": "<p>A theme: \"They shall never enter my rest\" — the oath of exclusion creates the negative space that makes Christ's rest-giving central. The rest that was forfeited by the wilderness generation is the rest that Christ opens through his completed work (4:10: he who enters God's rest rests from his own works, as God did from his). The exclusion-oath reveals what was lost; Christ's completed sacrifice reveals what is restored.</p>",
    "12": "<p>A theme: \"See to it that none of you has a sinful, unbelieving heart that turns away from the living God\" — the pastoral warning is directed at those who have the Son and are in danger of turning from him. The \"living God\" is the God who has spoken in the Son; to turn from him is to turn from the Son's very claim to be the definitive word. The warning passage is itself Christological: the danger of apostasy is defined by what one apostasizes from.</p>",
    "13": "<p>A theme: daily mutual encouragement holds the community in the present \"today\" of the Son's address. The community's shared life — gathering, exhortation, accountability — is the means by which the Son's word continues to reach each member. The Christological implication: the community gathered in the Son's name, hearing and obeying his word together, is the living form of the Son's ongoing ministry to his people.</p>",
    "14": "<p>A direct revelation: we have come to share in Christ, if we hold our original conviction firmly to the end. Participation in Christ (<em>metochoi tou Christou</em>) is the community's defining status — not merely following Jesus as a teacher but sharing in his person, his sonship, and his inheritance. The condition \"if we hold firm\" describes what the genuine sharing looks like in practice, not a doubt about whether those who hold firm truly share in Christ.</p>",
    "15": "<p>A theme: the Psalm's \"today\" repeated in the midst of the community's hearing is the Spirit's ongoing invitation to enter what Christ has opened. Each recitation of Psalm 95 is a fresh moment of decision — the same voice that spoke at Sinai, the same voice that speaks in the Son, the same voice that invites the community today to enter the rest that the wilderness generation forfeited.</p>",
    "16": "<p>A theme: the entire generation that Moses led out of Egypt heard and rebelled. The scope of the failure — not a minority but the majority — is a sobering context for the community. The exodus generation was privileged (they saw the plagues, the crossing, the Sinai theophany) yet failed. Their privilege without faith-response became their condemnation. The community who has seen the Son's greater privileges must take the greater-privilege/greater-responsibility logic seriously.</p>",
    "17": "<p>A theme: with those who sinned, whose bodies fell in the wilderness. The physical consequence of covenant unbelief — bodies falling in the wilderness, an entire generation dying without entering — is the historical evidence that God's oath was real and its consequences real. The eschatological consequence for those who reject the Son is analogically greater: if physical death in the wilderness was the consequence of Mosaic covenant unbelief, the ultimate consequence of new covenant rejection is proportionally more severe.</p>",
    "18": "<p>A theme: to those who disobeyed — the equation of disobedience and unbelief is the key to the entire wilderness warning section. Trust in God and obedience to God are the same response seen from different angles; the absence of one entails the absence of the other. Christ, who is both the object of faith (believe in him) and the Lord of obedience (obey him: 5:9), unifies the two in his own person.</p>",
    "19": "<p>A theme: they could not enter because of unbelief. The summary conclusion of the wilderness warning: the inability to enter the rest was not an external obstruction but an internal self-exclusion generated by unbelief. Faith is the instrument of entering the rest that Christ has opened; unbelief is the mechanism of self-exclusion. The door is open; the problem is the posture of those who will not walk through it.</p>"
  },
  "4": {
    "1": "<p>A theme: the promise of entering his rest still stands open. The rest that was forfeited by the wilderness generation has not been voided — it remains available through Christ who is both the rest-giver (his completed work is the basis of the rest) and the forerunner who has already entered the heavenly sanctuary as the community's pioneer. The exhortation to fear falling short is directed at those for whom the rest is genuinely available — those who have the Son.</p>",
    "2": "<p>A theme: the good news was proclaimed to them as to us, but they did not combine it with faith. The same gospel structure — divine promise, human reception, faith-response — applies to both the wilderness generation and the letter's community. The structural parallel reveals that salvation has always worked through the same mechanism: promise received by faith. Christ is the content of the promise that was proclaimed from the beginning; the wilderness generation's failure was not that they had the wrong promise but that they heard it without faith.</p>",
    "4": "<p>A type: God rested on the seventh day from all his works — the creation Sabbath is the primordial type of the eschatological rest that Christ opens. The rest into which faith enters is defined by the pattern of the creation Sabbath: completion of work (Gen 2:2 = finished creation; Heb 10:12 = the Son sat down, finished sacrifice), followed by cessation. Christ's completed work is the antitype of the creation Sabbath; entering his rest is entering the completion that his sacrifice achieved.</p>",
    "5": "<p>A theme: \"They shall never enter my rest\" — the oath-of-exclusion placed over the wilderness generation reveals the stakes of the covenant-promise. The rest is real and guarded; those who reject it by unbelief are specifically excluded by divine oath. The oath that excluded the wilderness generation is the same oath whose positive counterpart (the oath backing the Melchizedekian priesthood of Ps 110:4) secures the community's access through Christ.</p>",
    "6": "<p>A theme: some must still enter that rest, and the first generation's failure due to disobedience leaves it open. The logic of the still-open rest is Christological: the reason the rest remains available is that Christ has not yet completed the final gathering of all who will enter. The community addressed by Hebrews is the generation for whom Christ has opened the way; their entering completes what the wilderness generation left uncompleted.</p>",
    "7": "<p>A theme: God set a new \"today\" through David's Psalm — the ongoing scriptural \"today\" of Psalm 95 is the Spirit's continued opening of the entry-window. Each generation receives a fresh \"today\" because Christ's completed work is the eternal basis of the invitation. The chronological argument (David wrote Ps 95 after Joshua's Canaan-rest, proving the rest was still unfulfilled) points forward to the eschatological rest that Christ alone could open.</p>",
    "8": "<p>A type: if Joshua had given them rest, God would not have spoken of another day. Joshua is the OT type (Yehoshua = the same name as Jesus/Yeshua) whose partial, incomplete rest-giving points forward to the definitive rest-giving of Jesus. The type and antitype share the name as well as the pattern: the historical Joshua led Israel through the Jordan into Canaan; the eschatological Joshua/Jesus leads his people through death into the heavenly rest. The type's incompleteness proves it was always pointing beyond itself.</p>",
    "9": "<p>A direct revelation: there remains a Sabbath-rest for the people of God. The abiding nature of this rest is grounded in Christ's completed work: the \"remains\" is not an unfulfilled aspiration but the ongoing availability of what Christ has secured. The Sabbath-rest that \"remains\" is the rest into which the believing community enters now (the present dimension of 4:3: \"we who have believed are entering that rest\") and will enter fully at the parousia.</p>",
    "10": "<p>A type: anyone who enters God's rest also rests from their own work, as God did from his. The cessation from self-generated effort is the positive content of faith-entry into Christ's rest: faith is the opposite of works as a means of approach to God. Christ's own completed work (\"it is finished,\" John 19:30; he \"sat down,\" Heb 10:12) is the pattern for the community's rest-from-self-effort — not moral passivity but the cessation of self-justifying striving in favor of Christ's sufficient achievement.</p>",
    "11": "<p>A theme: let us make every effort to enter that rest, so no one falls by the same pattern of disobedience. The effort to enter rest is the effort of faith — actively orienting toward Christ rather than drifting. The warning is addressed to those within the community of promise who are in danger of replicating the wilderness generation's faith-failure. The Christological content: the rest to be entered is Christ's rest; the disobedience to be avoided is the refusal to trust the one who opened it.</p>",
    "12": "<p>A theme: the living and active word of God that penetrates to the innermost human reality is the word that speaks in the Son (1:2). The word's penetrating power is not an impersonal force but the address of the living God who speaks to the community through his Son and his Spirit. The word's discriminating function — exposing the thoughts and intentions of the heart — is the necessary prelude to the merciful access to the throne of grace (v16). The word reveals what needs grace; the throne of grace provides it.</p>",
    "13": "<p>A theme: nothing is hidden from God's sight, and all must give account. The divine omniscience and judicial role that v13 asserts is the context within which the community approaches the throne of grace (v16). Before the judge, the community is exposed; through the high priest, the community is covered. The transition from v13 (exposed before God's eyes) to v14-16 (boldly approaching the throne of grace through the great high priest) is the movement from law to gospel, from judgment to mercy.</p>",
    "16": "<p>A direct revelation: let us approach the throne of grace with confidence, to receive mercy and find grace to help in time of need. The throne of grace is the heavenly court where the risen Christ permanently intercedes (7:25). The confidence to approach is grounded in his completed sacrifice and ongoing intercession — not in the community's own worthiness. The mercy and grace available at the throne is the content of the salvation that the Son has secured by his own entry into the most holy place.</p>"
  },
  "5": {
    "1": "<p>A type: every high priest is taken from among humans and appointed to represent them before God. The Aaronic high priesthood is the institutional type whose structure — chosen from humans, representing humans, offering for sins — is fulfilled and exceeded in Christ. The type establishes what a genuine high priest must be (human, appointed, representative, sacrificing) so that when Christ meets all these criteria and exceeds them in each dimension, the argument for his superior priesthood is grounded in the type's own logic.</p>",
    "2": "<p>A type: the high priest's ability to deal gently with the ignorant and wayward, because he himself is subject to weakness, is the type of the sympathy Christ shows (4:15). The Levitical high priest sympathizes because he is weak; Christ sympathizes because he was tested. The type points to the genuine human solidarity of the high priest as essential to his function; the antitype fulfills this through the incarnation's actual entry into human weakness without itself becoming sinful.</p>",
    "3": "<p>A type: the high priest must offer for his own sins as well as the people's — this structural feature of the Levitical system points forward by contrast to the one who had no sins of his own to offer for. The self-offering requirement reveals both the Levitical high priest's limitation (he is himself a sinner) and Christ's surpassing qualification (he offered himself without sin, as the spotless sacrifice). The type is fulfilled by contrast: Christ does what the Levitical priest could not — offering himself as the untainted victim.</p>",
    "4": "<p>A type: no one takes the priestly honor on himself, but only one who is called by God. The divine-call requirement establishes the principle of legitimate appointment that Christ will fulfill through Psalm 110:4's oath. Aaron was called; Christ was called — but Christ's call comes with an oath that Aaron's did not, and from an order (Melchizedek's) that surpasses Aaron's. The shared principle (divine call required) links the type and antitype while the differences in the call's quality distinguish them.</p>",
    "7": "<p>A direct revelation: in the days of his flesh, the Son offered prayers and supplications with loud cries and tears, and was heard because of his reverence. The Gethsemane prayer is not a crisis of the incarnation but its most profound expression: the Son in the full reality of human anguish, bringing human need before the Father with complete trust. He was heard — not by removal of death but by resurrection through death. This reveals the character of the Son's high-priestly intercession: real petition, real anguish, real divine hearing.</p>",
    "9": "<p>A direct revelation: made perfect, he became the source of eternal salvation for all who obey him. The completed perfection-through-suffering is the qualification for the office whose benefit is eternal. The \"eternal\" salvation (aiōnios sōtēria) stands in contrast to the annual Yom Kippur atonement: what the Day of Atonement provided temporarily and cyclically, Christ provides permanently and finally. He is not one more source of atonement in a series but the singular source of the salvation that the entire atonement series was pointing toward.</p>",
    "11": "<p>A theme: there is much to say about Melchizedek but it is hard to explain because of spiritual dullness. The pastoral interruption is itself Christological: the community's inability to receive advanced Christological teaching (the Melchizedek priesthood) reflects their failure to grow into the fullness of what Christ is and has done. The depth of Christology corresponds to the depth of spiritual maturity — advancing in the faith means advancing in understanding the Son's priestly identity and work.</p>",
    "12": "<p>A theme: you need to be taught the elementary principles again rather than being teachers yourselves. The community's theological regression — needing to go back to basics — is a regression in Christological understanding. The \"solid food\" they are not ready for (v14) is precisely the Melchizedek theology of chs. 7-10: the full account of Christ's eternal high priesthood. Their spiritual immaturity is their inability to receive and hold the full Christological claim Hebrews is building toward.</p>",
    "13": "<p>A theme: whoever lives on milk is an infant, unskilled in the word of righteousness. The \"word of righteousness\" in context is the Christological word — the advanced teaching about Christ's priesthood and its achievement of the righteousness that the Levitical system could only symbolize. Spiritual infancy is Christological infancy: not knowing how to handle the teaching about the Son's identity and work with the maturity it requires.</p>",
    "14": "<p>A theme: solid food is for the mature who have trained their perceptual faculties to distinguish good from evil. The trained perception required for mature Christian faith is the ability to discern the depths of Christological truth — to see how Christ fulfills, surpasses, and replaces the Levitical system; to trace the typological connections; to hold the \"already\" and \"not yet\" in the appropriate tension. This is the theological formation that Hebrews is itself attempting to provide for the community.</p>"
  }
}
""")

def main():
    existing = load_comm("mkt-christ", "hebrews")
    merge_comm(existing, HEBREWS)
    save_comm("mkt-christ", "hebrews", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Hebrews 1-5 mkt-christ gaps filled: {len(existing)} chapters, {total} verses written.")

if __name__ == "__main__":
    main()
